    {
        _selfRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}

using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class SyncService
{
    private readonly LocalStorageService _storage;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _isSyncing;

    public event Action? SyncStatusChanged;
    public int PendingCount { get; private set; }

    public SyncService(LocalStorageService storage, ConnectivityService connectivity, HttpClient http)
    {
        _storage = storage;
        _connectivity = connectivity;
        _http = http;

        _connectivity.ConnectivityChanged += async (online) =>
        {
            if (online) await TrySyncAsync();
        };
    }

    public async Task TrySyncAsync()
    {
        if (_isSyncing || !_connectivity.IsOnline) return;

        _isSyncing = true;
        try
        {
            var pending = await _storage.GetPendingSyncInspectionsAsync();
            PendingCount = pending.Count;

            foreach (var inspection in pending)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.SyncStatus = SyncStatus.Synced;
                        await _storage.SaveInspectionAsync(inspection);
                        PendingCount--;
                    }
                    else
                    {
                        inspection.SyncStatus = SyncStatus.Failed;
                        await _storage.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    // Server unreachable — remain pending for next attempt
                }
            }
        }
        finally
        {
            _isSyncing = false;
            SyncStatusChanged?.Invoke();
        }
    }

    public async Task UpdatePendingCountAsync()
    {
        var pending = await _storage.GetPendingSyncInspectionsAsync();
        PendingCount = pending.Count;
        SyncStatusChanged?.Invoke();
    }
}

