@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _expandedItemId;
    private CancellationTokenSource? _debounceCts;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        // Toggle off if already set to same value
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        await SaveInspectionAsync();
    }

    private void ToggleItemNotes(string itemId)
    {
        _expandedItemId = _expandedItemId == itemId ? null : itemId;
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveInspectionAsync();
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        var file = e.File;
        // Resize to max 1200px wide to save storage
        var resized = await file.RequestImageFileAsync("image/jpeg", 1200, 1200);
        using var stream = resized.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new Photo
        {
            FileName = file.Name,
            DataBase64 = base64,
            TakenAt = DateTime.UtcNow
        };

        _inspection.Photos.Add(photo);
        await SaveInspectionAsync();
    }

    private async Task SetPhotoCaption(Photo photo, string caption)
    {
        photo.Caption = caption;
        await SaveInspectionAsync();
    }

    private async Task RemovePhoto(Photo photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveInspectionAsync();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.InspectedAt = DateTime.UtcNow;
        await SaveInspectionAsync();
        await Sync.TrySyncAsync();
    }

    private async Task SaveDebounced()
    {
        _debounceCts?.Cancel();
        _debounceCts = new CancellationTokenSource();
        var token = _debounceCts.Token;

        try
        {
            await Task.Delay(500, token);
            await SaveInspectionAsync();
        }
        catch (TaskCanceledException) { }
    }

    private async Task SaveInspectionAsync()
    {
        if (_inspection is null) return;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }

    private int GetCheckedCount() =>
        _inspection?.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked) ?? 0;

    private double GetPassPercent() =>
        _inspection is null || _inspection.ChecklistItems.Count == 0 ? 0 :
        100.0 * _inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass) / _inspection.ChecklistItems.Count;

    private double GetFailPercent() =>
