@page "/inspection/{InspectionId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject LocalStorageService Storage
@inject NavigationManager Nav
@inject SyncService Sync
@inject IJSRuntime JS

<div class="page-header">
    <button class="btn btn-outline-secondary" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
</div>

@if (_inspection is null)
{
    <p>Loading...</p>
}
else
{
    <!-- Tab navigation -->
    <ul class="nav nav-tabs nav-fill mb-3 sticky-tabs">
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "checklist" ? "active" : "")"
                    @onclick='() => _activeTab = "checklist"'>
                📋 Checklist
            </button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "photos" ? "active" : "")"
                    @onclick='() => _activeTab = "photos"'>
                📷 Photos (@_inspection.Photos.Count)
            </button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(_activeTab == "notes" ? "active" : "")"
                    @onclick='() => _activeTab = "notes"'>
                📝 Notes
            </button>
        </li>
    </ul>

    @if (_activeTab == "checklist")
    {
        <!-- Progress bar -->
        <div class="progress mb-3" style="height: 8px;">
            <div class="progress-bar bg-success" style="width: @GetPassPercent()%"></div>
            <div class="progress-bar bg-danger" style="width: @GetFailPercent()%"></div>
            <div class="progress-bar bg-secondary" style="width: @GetNaPercent()%"></div>
        </div>
        <p class="text-muted small text-center mb-2">
            @GetCheckedCount() / @_inspection.ChecklistItems.Count completed
        </p>

        @foreach (var group in _inspection.ChecklistItems.GroupBy(c => c.Category))
        {
            <div class="category-section">
                <h5 class="category-header">@group.Key</h5>
                @foreach (var item in group)
                {
                    <div class="checklist-item @GetItemClass(item)">
                        <div class="checklist-description" @onclick="() => ToggleItemNotes(item.Id)">
                            @item.Description
                        </div>
                        <div class="checklist-buttons">
                            <button class="btn btn-sm @(item.Result == CheckResult.Pass ? "btn-success" : "btn-outline-success")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)" @onclick:stopPropagation="true">✓</button>
                            <button class="btn btn-sm @(item.Result == CheckResult.Fail ? "btn-danger" : "btn-outline-danger")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)" @onclick:stopPropagation="true">✗</button>
                            <button class="btn btn-sm @(item.Result == CheckResult.NotApplicable ? "btn-secondary" : "btn-outline-secondary")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)" @onclick:stopPropagation="true">N/A</button>
                        </div>
                        @if (_expandedItemId == item.Id)
                        {
                            <div class="checklist-notes mt-2 w-100">
                                <input type="text" class="form-control form-control-sm"
                                       placeholder="Add note for this item..."
                                       value="@item.Notes"
                                       @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                            </div>
                        }
                    </div>
                }
            </div>
        }
    }
    else if (_activeTab == "photos")
    {
        <div class="mb-3">
            <label class="btn btn-primary btn-lg w-100">
                📷 Take Photo / Choose File
                <InputFile OnChange="HandlePhotoSelected" accept="image/*" capture="environment"
                           style="display:none" />
            </label>
        </div>

        @if (_inspection.Photos.Count == 0)
        {
            <p class="text-muted text-center">No photos yet. Tap above to add one.</p>
        }
        else
        {
            <div class="photo-grid">
                @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                {
                    <div class="photo-card">
                        <img src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" class="photo-thumb" />
                        <div class="photo-caption">
                            <input type="text" class="form-control form-control-sm" placeholder="Caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                        </div>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemovePhoto(photo)">Remove</button>
                    </div>
                }
            </div>
        }
    }
    else if (_activeTab == "notes")
    {
        <div class="mb-3">
            <label class="form-label">Inspector Name</label>
            <input type="text" class="form-control form-control-lg" placeholder="Your name"
                   @bind="_inspection.InspectorName" @bind:event="oninput" @bind:after="SaveDebounced" />
        </div>
        <div class="mb-3">
            <label class="form-label">General Notes</label>
            <textarea class="form-control" rows="6" placeholder="Site conditions, observations, concerns..."
                      @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveDebounced"></textarea>
        </div>
    }

    <!-- Footer action -->
    <div class="inspection-footer">
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn btn-success btn-lg w-100" @onclick="CompleteInspection">
                ✓ Complete Inspection
            </button>
        }
        else
        {
            <div class="alert alert-success text-center mb-0">
                ✓ Inspection completed @_inspection.InspectedAt.ToLocalTime().ToString("MMM dd, yyyy HH:mm")
            </div>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _expandedItemId;
    private CancellationTokenSource? _debounceCts;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        // Toggle off if already set to same value
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        await SaveInspectionAsync();
    }

    private void ToggleItemNotes(string itemId)
    {
        _expandedItemId = _expandedItemId == itemId ? null : itemId;
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveInspectionAsync();
    }

    private async Task HandlePhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        var file = e.File;
        // Resize to max 1200px wide to save storage
        var resized = await file.RequestImageFileAsync("image/jpeg", 1200, 1200);
        using var stream = resized.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);
        var base64 = Convert.ToBase64String(ms.ToArray());

        var photo = new Photo
        {
            FileName = file.Name,
            DataBase64 = base64,
            TakenAt = DateTime.UtcNow
        };

        _inspection.Photos.Add(photo);
        await SaveInspectionAsync();
    }

    private async Task SetPhotoCaption(Photo photo, string caption)
    {
        photo.Caption = caption;
        await SaveInspectionAsync();
    }

    private async Task RemovePhoto(Photo photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveInspectionAsync();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.InspectedAt = DateTime.UtcNow;
        await SaveInspectionAsync();
        await Sync.TrySyncAsync();
    }

    private async Task SaveDebounced()
    {
        _debounceCts?.Cancel();
        _debounceCts = new CancellationTokenSource();
        var token = _debounceCts.Token;

        try
        {
            await Task.Delay(500, token);
            await SaveInspectionAsync();
        }
        catch (TaskCanceledException) { }
    }

    private async Task SaveInspectionAsync()
    {
        if (_inspection is null) return;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }

    private int GetCheckedCount() =>
        _inspection?.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked) ?? 0;

    private double GetPassPercent() =>
        _inspection is null || _inspection.ChecklistItems.Count == 0 ? 0 :
        100.0 * _inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass) / _inspection.ChecklistItems.Count;

    private double GetFailPercent() =>
        _inspection is null || _inspection.ChecklistItems.Count == 0 ? 0 :
        100.0 * _inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail) / _inspection.ChecklistItems.Count;

    private double GetNaPercent() =>
        _inspection is null || _inspection.ChecklistItems.Count == 0 ? 0 :
        100.0 * _inspection.ChecklistItems.Count(c => c.Result == CheckResult.NotApplicable) / _inspection.ChecklistItems.Count;

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };
}

